package main

import (
	"sort"
)

func solve(piles []int64) int64 {
	sort.Slice(piles, func(i, j int) bool { return piles[i] < piles[j] })
	n := len(piles) / 3
	var sum int64
	for i := 0; i < n; i++ {
		index := len(piles) - 2 - 2*i
		sum += piles[index]
	}
	return sum
}
